import React, { useState } from 'react';
import logo from '../assets/logo.png';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';

const Login = ({ onBack, onSuccess }) => {
  const { login }  = useAuth();
  const [form, setForm]       = useState({ username: '', password: '' });
  const [showPwd, setShowPwd] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error,   setError]   = useState('');

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    if (!form.username || !form.password) { setError('Please enter your username and password.'); return; }
    setLoading(true);
    try {
      const data = await login(form);
      toast.success(`Welcome back, ${data.user.full_name}!`);
      onSuccess();
    } catch (err) {
      setError(err.response?.data?.message || 'Login failed. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-surface-bg flex">
      {/* Left panel */}
      <div className="hidden lg:flex w-5/12 bg-surface-card border-r border-surface-border flex-col justify-between p-10">
        <img src={logo} alt="K-POINT OF SALES" className="h-10 object-contain bg-white rounded-lg px-3 py-1 self-start" />
        <div>
          <h2 className="text-3xl font-800 text-text-primary leading-tight mb-4 tracking-tight">
            Welcome back<br/>to <span className="text-primary">K-POINT</span><br/>OF SALES
          </h2>
          <p className="text-sm text-text-muted leading-relaxed mb-8">Sign in to access your dashboard, process sales and manage your store.</p>
          <div className="flex flex-col gap-3">
            {['Secure 8-hour session token','Every login recorded in audit trail','Role-based access control','Works offline — no internet needed'].map(f => (
              <div key={f} className="flex items-center gap-3 text-sm text-text-muted">
                <div className="w-1.5 h-1.5 bg-primary rounded-full flex-shrink-0" />{f}
              </div>
            ))}
          </div>
        </div>
        <p className="text-xs text-text-faint">© 2025 K-POINT OF SALES · Maseru, Lesotho</p>
      </div>

      {/* Right panel */}
      <div className="flex-1 flex items-center justify-center p-6 bg-surface-panel">
        <div className="w-full max-w-sm">
          <button onClick={onBack} className="text-xs text-text-muted hover:text-primary mb-8 transition-colors">← Back</button>
          <h2 className="text-xl font-700 text-text-primary mb-1">Sign in</h2>
          <p className="text-sm text-text-muted mb-8">Enter your credentials to continue</p>

          {error && <div className="bg-danger/10 border border-danger/30 rounded-lg px-4 py-3 text-sm text-danger mb-4">{error}</div>}

          <form onSubmit={handleSubmit} className="space-y-5">
            <div>
              <label className="block text-xs font-500 text-text-muted uppercase tracking-wider mb-1.5">Username</label>
              <input type="text" className="k-input" placeholder="Enter your username" value={form.username} onChange={e => setForm({ ...form, username: e.target.value })} autoFocus />
            </div>
            <div>
              <label className="block text-xs font-500 text-text-muted uppercase tracking-wider mb-1.5">Password</label>
              <div className="relative">
                <input type={showPwd ? 'text' : 'password'} className="k-input pr-16" placeholder="Enter your password" value={form.password} onChange={e => setForm({ ...form, password: e.target.value })} />
                <button type="button" onClick={() => setShowPwd(!showPwd)} className="absolute right-3 top-1/2 -translate-y-1/2 text-xs text-text-faint hover:text-text-muted transition-colors">{showPwd ? 'Hide' : 'Show'}</button>
              </div>
            </div>
            <button type="submit" disabled={loading} className={`k-btn-primary w-full py-3.5 ${loading ? 'opacity-60 cursor-not-allowed' : ''}`}>
              {loading ? 'Signing in...' : 'Sign in'}
            </button>
          </form>
          <p className="text-center text-xs text-text-faint mt-8">K-POINT OF SALES <span className="text-primary">v1.0</span></p>
        </div>
      </div>
    </div>
  );
};

export default Login;
